import React, { createContext, useContext, useState, useEffect } from 'react';
import axios from 'axios';

const AuthContext = createContext(null);

const decodeJwtPayload = (token) => {
    try {
        const payload = token.split('.')[1];
        if (!payload) return null;
        const normalized = payload.replace(/-/g, '+').replace(/_/g, '/');
        const padded = normalized.padEnd(normalized.length + ((4 - (normalized.length % 4)) % 4), '=');
        return JSON.parse(atob(padded));
    } catch {
        return null;
    }
};

export const AuthProvider = ({ children }) => {
    const [user, setUser] = useState(() => {
        try {
            const saved = localStorage.getItem('user');
            return saved ? JSON.parse(saved) : null;
        } catch {
            return null;
        }
    });
    const [token, setToken] = useState(localStorage.getItem('token') || null);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        if (token) {
            localStorage.setItem('token', token);
            if (user) {
                localStorage.setItem('user', JSON.stringify(user));
            } else {
                const decoded = decodeJwtPayload(token);
                if (decoded?.id) {
                    const restoredUser = {
                        id: decoded.id,
                        role: decoded.role || 'patient',
                        name: decoded.name || ''
                    };
                    setUser(restoredUser);
                    localStorage.setItem('user', JSON.stringify(restoredUser));
                }
            }
        } else {
            localStorage.removeItem('token');
            localStorage.removeItem('user');
            setUser(null);
        }
        setLoading(false);
    }, [token, user]);

    const login = async (email, password, role) => {
        try {
            // Patient by default, or doctor based on role passed from login form
            const endpoint = role === 'doctor' ? '/api/doctors/login' : '/api/patients/login';
            const response = await axios.post(`http://localhost:3000${endpoint}`, { email, password }, { timeout: 10000 });
            
            setToken(response.data.token);
            const loggedInUser = role === 'doctor' ? response.data.doctor : response.data.patient;
            setUser({ ...loggedInUser, role }); // Explicitly store role
            
            return { success: true, role };
        } catch (error) {
            console.error('Login error:', error.response?.data?.error || error.message);
            if (!error.response) {
                return {
                    success: false,
                    error: 'Backend is unreachable. Start Docker Desktop and run: docker compose up --build -d'
                };
            }
            return { success: false, error: error.response?.data?.error || 'Login failed' };
        }
    };

    const register = async (userData, role) => {
        try {
            const endpoint = role === 'doctor' ? '/api/doctors/register' : '/api/patients/register';
            const response = await axios.post(`http://localhost:3000${endpoint}`, userData, { timeout: 10000 });
            return { success: true }; // Registration doesn't auto-login currently
        } catch (error) {
            if (!error.response) {
                return {
                    success: false,
                    error: 'Backend is unreachable. Start Docker Desktop and run: docker compose up --build -d'
                };
            }
            return { success: false, error: error.response?.data?.error || 'Registration failed' };
        }
    };

    const logout = () => {
        setToken(null);
        setUser(null);
        localStorage.removeItem('user');
    };

    return (
        <AuthContext.Provider value={{ user, token, login, logout, register, loading }}>
            {children}
        </AuthContext.Provider>
    );
};

export const useAuth = () => useContext(AuthContext);
